const __pageData = JSON.parse('{"title":"NestJS 教程 15：Redis 缓存实战","description":"本教程介绍 Redis 的基础知识和在 NestJS 中的应用，包括 Redis 的安装、常用命令（字符串、列表、集合、有序集合、哈希、地理空间、位图），以及在 NestJS 中实现购物车缓存功能的完整案例。","frontmatter":{"title":"NestJS 教程 15：Redis 缓存实战","date":"2026-03-04T00:00:00.000Z","description":"本教程介绍 Redis 的基础知识和在 NestJS 中的应用，包括 Redis 的安装、常用命令（字符串、列表、集合、有序集合、哈希、地理空间、位图），以及在 NestJS 中实现购物车缓存功能的完整案例。"},"headers":[],"relativePath":"tutorials/nestjs/nestjs-tutorial-15-redis.md","filePath":"tutorials/nestjs/nestjs-tutorial-15-redis.md"}');
